const cfg = $('Workflow Configuration').first().json;
const maxQueries = Number(cfg.maxQueriesPerRun || 20);
const now = Date.now();
const statusOf = row => String(row.status || '').toUpperCase();
const isDue = row => !row.next_retry_at || Date.parse(row.next_retry_at) <= now;
const leaseExpired = row => !row.lease_until || Date.parse(row.lease_until) <= now;
const selectable = row => {
  const status = statusOf(row);
  if (['READY', 'PENDING_REFRESH', 'FAILED_RETRYABLE'].includes(status)) return true;
  return status === 'RUNNING' && leaseExpired(row);
};
return $input.all()
  .map(item => item.json)
  .filter(row => selectable(row))
  .filter(row => Number(row.attempt_count || 0) < Number(row.max_attempts || cfg.maxAttempts || 3))
  .filter(row => isDue(row) && leaseExpired(row))
  .slice(0, maxQueries)
  .map(row => ({ json: row }));

const cfg = $('Workflow Configuration').first().json;
const now = new Date();
const leaseUntil = new Date(now.getTime() + Number(cfg.leaseMinutes || 30) * 60 * 1000).toISOString();
const leaseOwner = `maps-collector:${$execution.id || Date.now()}`;
return $input.all().map(item => ({
  json: {
    ...item.json,
    search_job_id: item.json.search_job_id || item.json.queue_key,
    queue_key: item.json.queue_key || item.json.search_job_id,
    status: 'RUNNING',
    attempt_count: Number(item.json.attempt_count || 0) + 1,
    max_attempts: Number(item.json.max_attempts || cfg.maxAttempts || 3),
    last_run_at: now.toISOString(),
    next_retry_at: '',
    lease_owner: leaseOwner,
    lease_until: leaseUntil,
    last_error_code: '',
    last_error: '',
    created_at: item.json.created_at || now.toISOString(),
    updated_at: now.toISOString(),
    schema_version: item.json.schema_version || 'v1',
  },
}));

const cfg = $('Workflow Configuration').first().json;
return $input.all().map(item => ({
  json: {
    ...item.json,
    apify_url: `https://api.apify.com/v2/acts/${cfg.apifyActorId}/run-sync-get-dataset-items`,
    apify_request: {
      searchStringsArray: [item.json.keyword === 'med spa near me' ? 'med spa' : item.json.keyword],
      locationQuery: `${item.json.city}, ${item.json.state}, USA`,
      maxCrawledPlacesPerSearch: Number(cfg.maxCrawledPlacesPerSearch || 10),
      language: cfg.language,
      includeWebResults: false,
      scrapeSocialMediaProfiles: {
        facebooks: false,
        instagrams: false,
        youtubes: false,
        tiktoks: false,
        twitters: false
      },
      maximumLeadsEnrichmentRecords: 0,
      maxImages: 0
    }
  }
}));

const requestItems = $('Build Apify Request').all();
const now = new Date().toISOString();
const normalizeDomain = (value = '') => String(value || '').replace(/^https?:\/\//i, '').replace(/^www\./i, '').split('/')[0].toLowerCase();
const normalizePhone = (value = '') => String(value || '').replace(/\D+/g, '');
const normalizeName = value => String(value || '').trim().toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
const slugify = value => String(value || '').toLowerCase().replace(/[^a-z0-9|]+/g, '-').replace(/^-+|-+$/g, '');
function identityFor(place, source, businessName, website, phone) {
  const domain = normalizeDomain(website);
  const googlePlaceId = place.placeId || place.place_id || place.cid || '';
  const phoneDigits = normalizePhone(phone);
  if (domain) return ['domain', domain];
  if (googlePlaceId) return ['google_place_id', String(googlePlaceId).toLowerCase()];
  if (phoneDigits) return ['phone', phoneDigits];
  return ['name_city_state', normalizeName(businessName) + '|' + normalizeName(source.city) + '|' + normalizeName(source.state)];
}
return $input.all().map((item, index) => {
  const paired = item.pairedItem;
  const sourceIndex = Array.isArray(paired) ? paired[0]?.item : paired?.item;
  const source = requestItems[sourceIndex ?? index]?.json || requestItems[0]?.json || {};
  const place = item.json;
  const businessName = place.title || place.name || place.businessName || '';
  const website = place.website || place.websiteUrl || '';
  const phone = place.phone || place.phoneNumber || place.phoneUnformatted || '';
  const [identityStrategy, identityKey] = identityFor(place, source, businessName, website, phone);
  const leadId = slugify(identityStrategy + '|' + identityKey);
  const domain = normalizeDomain(website);
  return {
    json: {
      lead_id: leadId,
      raw_result_key: leadId,
      dedupe_key: leadId,
      identity_strategy: identityStrategy,
      identity_key: identityKey,
      duplicate_of_lead_id: '',
      search_job_id: source.search_job_id || source.queue_key,
      queue_key: source.queue_key || source.search_job_id,
      apify_run_id: source.apify_run_id || '',
      apify_dataset_id: source.apify_dataset_id || '',
      google_place_id: place.placeId || place.place_id || place.cid || '',
      city: source.city,
      state: source.state,
      state_code: source.state_code || '',
      country: 'US',
      keyword: source.keyword,
      source_query_template: source.source_query_template,
      source_query_executed: source.source_query_executed,
      business_name: businessName,
      business_name_normalized: normalizeName(businessName),
      category: place.categoryName || place.category || '',
      full_address: place.address || place.fullAddress || '',
      phone,
      phone_e164: normalizePhone(phone) ? '+' + normalizePhone(phone) : '',
      website,
      domain,
      google_maps_url: place.url || place.placeUrl || '',
      rating: place.totalScore || place.rating || '',
      review_count: place.reviewsCount || place.reviews || '',
      matched_keywords: source.keyword,
      pipeline_status: 'SCRAPED',
      status: 'SCRAPED',
      qualification_status: 'unknown',
      stage: 'maps',
      attempt_count: 0,
      max_attempts: 3,
      next_retry_at: '',
      lease_owner: '',
      lease_until: '',
      first_seen_at: now,
      last_seen_at: now,
      last_checked_at: '',
      last_error_stage: '',
      last_error_code: '',
      last_error: '',
      schema_version: 'v1',
      created_at: now,
      updated_at: now,
    }
  };
}).filter(item => item.json.business_name || item.json.website || item.json.phone);

const sourceItems = $('Mark Queries Processing').all();
const now = new Date().toISOString();
const retryAt = attempt => new Date(Date.now() + Math.min(360, 15 * Math.pow(4, Math.max(0, attempt - 1))) * 60 * 1000).toISOString();
const outputs = [];
const seen = new Set();
const items = $input.all();
const getSourceIndex = item => {
  const paired = item.pairedItem;
  if (Array.isArray(paired)) return paired[0]?.item;
  return paired?.item;
};
const getPayload = value => {
  if (Array.isArray(value)) return value;
  if (Array.isArray(value?.body)) return value.body;
  if (Array.isArray(value?.data)) return value.data;
  if (value?.body && typeof value.body === 'object' && Object.keys(value.body).length) return value.body;
  if (value?.data && typeof value.data === 'object' && Object.keys(value.data).length) return value.data;
  return value;
};
for (const item of items) {
  const sourceIndex = getSourceIndex(item);
  if (sourceIndex == null || seen.has(sourceIndex)) continue;
  seen.add(sourceIndex);
  const source = sourceItems[sourceIndex]?.json;
  if (!source) continue;
  const payload = getPayload(item.json);
  const looksLikePlace = payload && typeof payload === 'object' && !Array.isArray(payload) && (payload.title || payload.name || payload.businessName || payload.website || payload.phone || payload.address);
  const resultCount = Array.isArray(payload) ? payload.length : (looksLikePlace ? 1 : 0);
  const isError = resultCount === 0 && (item.json?.errorMessage || item.json?.message || item.json?.statusCode >= 400);
  const attempts = Number(source.attempt_count || 1);
  const maxAttempts = Number(source.max_attempts || 3);
  outputs.push({
    json: {
      ...source,
      search_job_id: source.search_job_id || source.queue_key,
      queue_key: source.queue_key || source.search_job_id,
      status: isError ? (attempts >= maxAttempts ? 'FAILED_TERMINAL' : 'FAILED_RETRYABLE') : (resultCount > 0 ? 'COMPLETED' : 'NO_RESULTS'),
      result_count: resultCount,
      next_retry_at: isError && attempts < maxAttempts ? retryAt(attempts) : '',
      lease_owner: '',
      lease_until: '',
      last_error_code: isError ? String(item.json?.statusCode || 'APIFY_ERROR') : '',
      last_error: isError ? String(item.json?.errorMessage || item.json?.message || `HTTP ${item.json?.statusCode || 'error'}`) : '',
      updated_at: now,
      completed_at: !isError ? now : '',
      schema_version: source.schema_version || 'v1',
    }
  });
}
return outputs;

const now = new Date().toISOString();
return $input.all().map(item => ({
  json: {
    event_id: 'maps-' + (item.json.lead_id || item.json.raw_result_key) + '-' + Date.now(),
    lead_id: item.json.lead_id || item.json.raw_result_key || '',
    search_job_id: item.json.search_job_id || item.json.queue_key || '',
    workflow_name: 'med-spa-maps-collector',
    execution_id: String($execution.id || ''),
    from_status: 'NEW',
    to_status: item.json.pipeline_status || item.json.status || 'SCRAPED',
    stage: 'maps',
    message: 'Lead scraped from Apify Google Maps result',
    event_payload: JSON.stringify({ business_name: item.json.business_name, website: item.json.website, phone: item.json.phone, keyword: item.json.keyword }),
    created_at: now,
  }
}));

const now = new Date().toISOString();
return $input.all()
  .map(item => item.json)
  .filter(row => ['FAILED_RETRYABLE', 'FAILED_TERMINAL'].includes(String(row.status || '').toUpperCase()))
  .map(row => ({
    json: {
      error_id: 'maps-' + (row.search_job_id || row.queue_key || Date.now()) + '-' + Date.now(),
      workflow_name: 'med-spa-maps-collector',
      execution_id: String($execution.id || ''),
      record_type: 'search_job',
      record_id: row.search_job_id || row.queue_key || '',
      lead_id: '',
      search_job_id: row.search_job_id || row.queue_key || '',
      stage: 'maps',
      attempt_count: row.attempt_count || 0,
      error_code: row.last_error_code || 'APIFY_ERROR',
      error_message: row.last_error || '',
      raw_error_json: JSON.stringify(row),
      retryable: String(row.status || '').toUpperCase() === 'FAILED_RETRYABLE' ? 'true' : 'false',
      next_retry_at: row.next_retry_at || '',
      created_at: now,
    }
  }));
